#!/usr/bin/env node
// ===========================================================================
//  Doom-Rooms major update — run this from your project's "ldd" folder
//  (the one with package.json):   node apply.mjs
//
//  Applies: massive open rooms + random branching corridors, vertical mouse
//  look (up/down), forward-facing gun viewmodel, wall/ceiling stains,
//  furniture that clips through walls, and a 640x360 render resolution.
//
//  It OVERWRITES three files and saves a .bak of each first:
//    src/lib/chunkManager.js, src/lib/raycaster.js,
//    src/components/game/GameEngine.jsx
// ===========================================================================
import fs from 'fs';
import path from 'path';

const FILES = {
  "src/lib/chunkManager.js": "",
  "src/lib/raycaster.js": "",
  "src/components/game/GameEngine.jsx": "",
};

function findRoot() {
  let dir = process.cwd();
  for (let i = 0; i < 6; i++) {
    if (fs.existsSync(path.join(dir, 'src', 'lib')) && fs.existsSync(path.join(dir, 'package.json'))) return dir;
    const nested = path.join(dir, 'backrooms-doom-edition', 'ldd');
    if (fs.existsSync(path.join(nested, 'src', 'lib'))) return nested;
    const nested2 = path.join(dir, 'ldd');
    if (fs.existsSync(path.join(nested2, 'src', 'lib'))) return nested2;
    const up = path.dirname(dir);
    if (up === dir) break;
    dir = up;
  }
  return null;
}

const root = findRoot();
if (!root) {
  console.error('\n  Could not find the project. cd into the folder that has package.json and src/ (usually .../backrooms-doom-edition/ldd) and run:  node apply.mjs\n');
  process.exit(1);
}
console.log('Project root:', root);

let n = 0;
for (const [rel, b64] of Object.entries(FILES)) {
  const dest = path.join(root, rel);
  if (!fs.existsSync(path.dirname(dest))) {
    console.error('  ! Missing folder for ' + rel + ' — wrong project root?');
    process.exit(1);
  }
  if (fs.existsSync(dest)) fs.copyFileSync(dest, dest + '.bak');
  fs.writeFileSync(dest, Buffer.from(b64, 'base64').toString('utf8'));
  console.log('  updated ' + rel + (fs.existsSync(dest + '.bak') ? '  (backup: ' + rel + '.bak)' : ''));
  n++;
}
console.log('\n  Done — ' + n + ' files updated.\n  Next:  npm install   (first time only)\n         npm run dev\n\n  Tip: room size & hallway width are the HALL_W / ROOM constants at the top of\n  src/lib/chunkManager.js; render resolution is SCREEN_WIDTH/HEIGHT at the top\n  of src/lib/raycaster.js (lower them if it runs slow).\n');
